  -moz-animation: grow 1s 1;
  -webkit-animation: grow 1s 1;
  -ms-animation: grow 1s 1;
  animation: grow 1s 1;
  height: 10px;
  width: 10px;
  position: absolute;
  background-color: blue;
  opacity: 0;
  border-radius: 100%;
}
